239→/// Compatibility accessor: returns kit IDs as strings.
240→/// For callers that only need the kit identifier strings.
241→pub fn vofc_distributable_kit_ids() -> Vec<String> {
242→    DISTRIBUTABLE_KITS.iter().map(|k| k.cipher.kit_id()).collect()
243→}
244→
245→/// Find a kit by its ID (e.g., "jjk", "buk").
246→pub fn vofc_find_kit_by_id(kit_id: &str) -> Option<&'static vofc_Kit> {
247→    DISTRIBUTABLE_KITS.iter().find(|k| k.cipher.kit_id() == kit_id)
248→}
249→
250→// =============================================================================
251→// Claude Asset Signets
252→// =============================================================================
253→
254→/// Command signet suffix (appears after cipher prefix)
255→/// Pattern: {cipher}c-*.md
256→pub const VOFC_COMMAND_SIGNET_SUFFIX: &str = "c-";
257→
258→/// Hook signet suffix (appears after cipher prefix)
259→/// Pattern: {cipher}h-*.md
260→pub const VOFC_HOOK_SIGNET_SUFFIX: &str = "h-";
261→
262→/// Find a cipher by prefix.
263→pub fn vofc_find_by_prefix(prefix: &str) -> Option<&'static vofc_Cipher> {
264→    ALL_CIPHERS.iter().find(|c| c.prefix == prefix)
265→}
266→
267→/// Check if a prefix is registered.
268→pub fn vofc_is_registered(prefix: &str) -> bool {
269→    vofc_find_by_prefix(prefix).is_some()
270→}
271→
272→/// Validate terminal exclusivity: ensure no prefix is a prefix of another.
273→/// Returns None if valid, or Some pair of conflicting ciphers.
274→pub fn vofc_validate_terminal_exclusivity() -> Option<(&'static vofc_Cipher, &'static vofc_Cipher)> {
275→    for (i, a) in ALL_CIPHERS.iter().enumerate() {
276→        for b in ALL_CIPHERS.iter().skip(i + 1) {
277→            if a.prefix.starts_with(b.prefix) || b.prefix.starts_with(a.prefix) {
278→                return Some((a, b));
279→            }
280→        }
281→    }
282→    None
283→}
