413→/// Result of forge freshen operation.
414→#[derive(Debug)]
415→pub struct vofe_FreshenResult {
416→    /// CLAUDE.md sections updated (replaced existing markers)
417→    pub updated: Vec<String>,
418→    /// CLAUDE.md sections expanded (from UNINSTALLED markers)
419→    pub expanded: Vec<String>,
420→    /// CLAUDE.md sections appended (no prior markers)
421→    pub appended: Vec<String>,
