424→/// Freshen CLAUDE.md managed sections from kit forge source templates.
425→///
426→/// Reads templates directly from Tools/{kit}/vov_veiled/ (bypassing parcel pipeline).
427→/// Does NOT commit — caller decides when to commit.
428→///
429→/// # Arguments
430→/// * `burc_path` - Path to target repo's burc.env file
431→///
432→/// # Returns
433→/// FreshenResult with update summary, or error message
434→pub fn vofe_freshen_forge(burc_path: &Path) -> Result<vofe_FreshenResult, String> {
435→    let burc = vofe_parse_burc(burc_path)?;
436→
437→    // Read templates from forge vov_veiled/ directories
438→    let mut sections = Vec::new();
439→    for kit_id in &burc.managed_kits {
440→        let kit = vofc_find_kit_by_id(kit_id)
441→            .ok_or_else(|| format!("Kit not in registry: {}", kit_id))?;
442→
443→        let veiled_dir = burc.tools_dir.join(kit_id).join("vov_veiled");
444→
445→        for section in kit.managed_sections {
446→            let template_path = veiled_dir.join(section.template_path);
447→            if !template_path.exists() {
448→                return Err(format!(
449→                    "Template not found in forge: {} (expected at {})",
450→                    section.template_path,
451→                    template_path.display()
452→                ));
453→            }
454→
455→            let content = fs::read_to_string(&template_path)
456→                .map_err(|e| format!("Failed to read template {}: {}", section.template_path, e))?;
457→
458→            sections.push(voff_ManagedSection {
459→                tag: section.tag.to_string(),
460→                content,
461→            });
462→        }
463→    }
464→
465→    // Freshen CLAUDE.md
466→    let claude_path = burc.project_root.join("CLAUDE.md");
467→    let existing = if claude_path.exists() {
468→        fs::read_to_string(&claude_path)
469→            .map_err(|e| format!("Failed to read CLAUDE.md: {}", e))?
470→    } else {
471→        "# Claude Code Project Memory\n".to_string()
472→    };
473→
474→    let result = voff_freshen(&existing, &sections);
475→
476→    fs::write(&claude_path, &result.content)
477→        .map_err(|e| format!("Failed to write CLAUDE.md: {}", e))?;
478→
479→    // Report what happened
480→    for tag in &result.updated {
481→        eprintln!("  freshen: updated [{}]", tag);
482→    }
483→    for tag in &result.expanded {
484→        eprintln!("  freshen: expanded [{}] (was UNINSTALLED)", tag);
485→    }
486→    for tag in &result.appended {
487→        eprintln!("  freshen: appended [{}] (new section)", tag);
488→    }
489→
490→    Ok(vofe_FreshenResult {
491→        updated: result.updated,
492→        expanded: result.expanded,
493→        appended: result.appended,
494→    })
495→}
