501→/// Parse burc.env file to extract environment variables.
502→/// BURC_PROJECT_ROOT is the path from burc.env's location to the project root.
503→/// BURC_TOOLS_DIR is resolved relative to the resolved project_root (per BURC spec).
504→pub fn vofe_parse_burc(path: &Path) -> Result<vofe_BurcEnv, String> {
505→    if !path.exists() {
506→        return Err(format!("burc.env not found: {}", path.display()));
507→    }
508→
509→    // Get the parent directory of burc.env for path resolution
510→    let burc_parent = path
511→        .parent()
512→        .ok_or_else(|| "burc.env path has no parent directory".to_string())?;
513→
514→    let content = fs::read_to_string(path)
515→        .map_err(|e| format!("Failed to read burc.env: {}", e))?;
516→
517→    let mut vars: HashMap<String, String> = HashMap::new();
518→
519→    for line in content.lines() {
520→        let line = line.trim();
521→
522→        // Skip comments and empty lines
523→        if line.is_empty() || line.starts_with('#') {
524→            continue;
525→        }
526→
527→        // Parse KEY=VALUE (handle quoted values)
528→        if let Some(eq_pos) = line.find('=') {
529→            let key = line[..eq_pos].trim();
530→            let mut value = line[eq_pos + 1..].trim();
531→
532→            // Remove surrounding quotes if present
533→            if (value.starts_with('"') && value.ends_with('"'))
534→                || (value.starts_with('\'') && value.ends_with('\''))
535→            {
536→                value = &value[1..value.len() - 1];
537→            }
538→
539→            vars.insert(key.to_string(), value.to_string());
540→        }
541→    }
542→
543→    let tools_dir_str = vars
544→        .get("BURC_TOOLS_DIR")
545→        .ok_or_else(|| "burc.env missing required variable: BURC_TOOLS_DIR".to_string())?;
546→
547→    let project_root_str = vars
548→        .get("BURC_PROJECT_ROOT")
549→        .ok_or_else(|| "burc.env missing required variable: BURC_PROJECT_ROOT".to_string())?;
550→
551→    // BURC_PROJECT_ROOT is the path from burc.env's location to project root
552→    let project_root = burc_parent.join(project_root_str);
553→    let project_root = project_root
554→        .canonicalize()
555→        .map_err(|e| format!("BURC_PROJECT_ROOT path invalid ({}): {}", project_root.display(), e))?;
556→
557→    // Resolve tools_dir relative to project_root (per BURC spec)
558→    let tools_dir = project_root.join(tools_dir_str);
559→    let tools_dir = tools_dir
560→        .canonicalize()
561→        .map_err(|e| format!("BURC_TOOLS_DIR path invalid ({}): {}", tools_dir.display(), e))?;
562→
563→    // Parse BURC_MANAGED_KITS (comma-separated list)
564→    let managed_kits_str = vars
565→        .get("BURC_MANAGED_KITS")
566→        .ok_or_else(|| "burc.env missing required variable: BURC_MANAGED_KITS".to_string())?;
567→
568→    let managed_kits: Vec<String> = managed_kits_str
569→        .split(',')
570→        .map(|s| s.trim().to_string())
571→        .filter(|s| !s.is_empty())
572→        .collect();
573→
574→    if managed_kits.is_empty() {
575→        return Err("BURC_MANAGED_KITS must specify at least one kit".to_string());
576→    }
577→
578→    Ok(vofe_BurcEnv {
579→        tools_dir,
580→        project_root,
581→        managed_kits,
582→    })
583→}
