585→/// Read brand file and extract hallmark and kit list.
586→fn zvofe_read_brand(path: &Path) -> Result<(u32, Vec<String>), String> {
587→    if !path.exists() {
588→        return Err(format!("Brand file not found: {}", path.display()));
589→    }
590→
591→    let content = fs::read_to_string(path)
592→        .map_err(|e| format!("Failed to read brand file: {}", e))?;
593→
594→    let json: serde_json::Value = serde_json::from_str(&content)
595→        .map_err(|e| format!("Failed to parse brand JSON: {}", e))?;
596→
597→    let hallmark = json
598→        .get(VOFE_BRAND_HALLMARK)
599→        .and_then(|v| v.as_u64())
600→        .map(|v| v as u32)
601→        .ok_or_else(|| "Brand file missing hallmark".to_string())?;
602→
603→    let kits = json
604→        .get(VOFE_BRAND_KITS)
605→        .and_then(|v| v.as_array())
606→        .ok_or_else(|| "Brand file missing kits array".to_string())?;
607→
608→    let kit_ids: Vec<String> = kits
609→        .iter()
610→        .filter_map(|v| v.as_str().map(String::from))
611→        .collect();
612→
613→    if kit_ids.is_empty() {
614→        return Err("Brand file has empty kits array".to_string());
615→    }
616→
617→    Ok((hallmark, kit_ids))
618→}
