684→/// Walk directory recursively, returning all file paths.
685→fn zvofe_walk_dir(dir: &Path) -> Result<Vec<PathBuf>, String> {
686→    let mut files = Vec::new();
687→
688→    if !dir.is_dir() {
689→        return Ok(files);
690→    }
691→
692→    let entries = fs::read_dir(dir)
693→        .map_err(|e| format!("Failed to read dir {}: {}", dir.display(), e))?;
694→
695→    for entry in entries {
696→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
697→        let path = entry.path();
698→
699→        if path.is_dir() {
700→            files.extend(zvofe_walk_dir(&path)?);
701→        } else {
702→            files.push(path);
703→        }
704→    }
705→
706→    Ok(files)
707→}
