709→/// Check if file is a command file (matches {cipher}c-*.md pattern).
710→fn zvofe_is_command_file(file_name: &str, cipher: &str) -> bool {
711→    let prefix = format!("{}{}", cipher, VOFC_COMMAND_SIGNET_SUFFIX);
712→    file_name.starts_with(&prefix) && file_name.ends_with(".md")
713→}
714→
715→/// Check if file is a hook file (matches {cipher}h-*.md pattern).
716→fn zvofe_is_hook_file(file_name: &str, cipher: &str) -> bool {
717→    let prefix = format!("{}{}", cipher, VOFC_HOOK_SIGNET_SUFFIX);
718→    file_name.starts_with(&prefix) && file_name.ends_with(".md")
719→}
