721→/// Route Claude config assets from parcel claude/* to target .claude/*.
722→/// Returns (commands_routed, hooks_routed).
723→fn zvofe_route_claude_assets(
724→    parcel_dir: &Path,
725→    project_root: &Path,
726→) -> Result<(u32, u32), String> {
727→    let mut commands_count = 0u32;
728→    let mut hooks_count = 0u32;
729→
730→    // Route commands from parcel claude/commands/ to target .claude/commands/
731→    let commands_source = parcel_dir.join("claude").join("commands");
732→    if commands_source.exists() {
733→        let commands_dest = project_root.join(".claude").join("commands");
734→        fs::create_dir_all(&commands_dest)
735→            .map_err(|e| format!("Failed to create .claude/commands dir: {}", e))?;
736→
737→        commands_count = zvofe_copy_all_files(&commands_source, &commands_dest)?;
738→    }
739→
740→    // Route hooks from parcel claude/hooks/ to target .claude/hooks/
741→    let hooks_source = parcel_dir.join("claude").join("hooks");
742→    if hooks_source.exists() {
743→        let hooks_dest = project_root.join(".claude").join("hooks");
744→        fs::create_dir_all(&hooks_dest)
745→            .map_err(|e| format!("Failed to create .claude/hooks dir: {}", e))?;
746→
747→        hooks_count = zvofe_copy_all_files(&hooks_source, &hooks_dest)?;
748→    }
749→
750→    Ok((commands_count, hooks_count))
751→}
