753→/// Copy all files from source directory to dest directory.
754→/// Returns count of files copied.
755→fn zvofe_copy_all_files(source_dir: &Path, dest_dir: &Path) -> Result<u32, String> {
756→    let mut count = 0u32;
757→
758→    let entries = fs::read_dir(source_dir)
759→        .map_err(|e| format!("Failed to read directory {}: {}", source_dir.display(), e))?;
760→
761→    for entry in entries {
762→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
763→        let path = entry.path();
764→
765→        if !path.is_file() {
766→            continue;
767→        }
768→
769→        let file_name = path
770→            .file_name()
771→            .ok_or_else(|| format!("No file name for {}", path.display()))?;
772→
773→        let dest_path = dest_dir.join(file_name);
774→        fs::copy(&path, &dest_path)
775→            .map_err(|e| format!("Failed to copy {} to {}: {}", path.display(), dest_path.display(), e))?;
776→        count += 1;
777→    }
778→
779→    Ok(count)
780→}
