782→/// Read managed section templates from parcel.
783→fn zvofe_read_templates(
784→    parcel_dir: &Path,
785→    kit_ids: &[String],
786→) -> Result<Vec<voff_ManagedSection>, String> {
787→    let mut sections = Vec::new();
788→
789→    for kit_id in kit_ids {
790→        let kit = vofc_find_kit_by_id(kit_id)
791→            .ok_or_else(|| format!("Kit not in registry: {}", kit_id))?;
792→
793→        let templates_dir = parcel_dir.join("kits").join(kit_id).join("templates");
794→
795→        for section in kit.managed_sections {
796→            let template_path = templates_dir.join(section.template_path);
797→            if !template_path.exists() {
798→                return Err(format!(
799→                    "Template not found in parcel: {}",
800→                    template_path.display()
801→                ));
802→            }
803→
804→            let content = fs::read_to_string(&template_path)
805→                .map_err(|e| format!("Failed to read template {}: {}", section.template_path, e))?;
806→
807→            sections.push(voff_ManagedSection {
808→                tag: section.tag.to_string(),
809→                content,
810→            });
811→        }
812→    }
813→
814→    Ok(sections)
815→}
