840→/// Collapse CLAUDE.md managed sections to UNINSTALLED markers.
841→fn zvofe_collapse_claude(claude_path: &Path, tags: &[String]) -> Result<(), String> {
842→    if !claude_path.exists() {
843→        return Ok(()); // Nothing to collapse
844→    }
