858→/// Remove files matching a pattern from a directory.
859→/// If is_command is true, matches {cipher}c-*.md; otherwise matches {cipher}h_*
860→/// Returns count of files removed.
861→fn zvofe_remove_matching_files(dir: &Path, cipher: &str, is_command: bool) -> Result<u32, String> {
862→    let mut count = 0u32;
863→
864→    let entries = fs::read_dir(dir)
865→        .map_err(|e| format!("Failed to read directory {}: {}", dir.display(), e))?;
866→
867→    for entry in entries {
868→        let entry = entry.map_err(|e| format!("Dir entry error: {}", e))?;
869→        let path = entry.path();
870→
871→        if !path.is_file() {
872→            continue;
873→        }
874→
875→        let file_name = path
876→            .file_name()
877→            .and_then(|n| n.to_str())
878→            .unwrap_or("");
879→
880→        let matches = if is_command {
881→            zvofe_is_command_file(file_name, cipher)
882→        } else {
883→            zvofe_is_hook_file(file_name, cipher)
884→        };
885→
886→        if matches {
887→            fs::remove_file(&path)
888→                .map_err(|e| format!("Failed to remove {}: {}", path.display(), e))?;
889→            count += 1;
890→        }
891→    }
892→
893→    Ok(count)
894→}
