481→/// Load registry from JSON file.
482→fn zvofr_load_registry(path: &Path) -> Result<BTreeMap<u32, vofr_RegistryEntry>, String> {
483→    if !path.exists() {
484→        return Ok(BTreeMap::new());
485→    }
486→
487→    let content = fs::read_to_string(path)
488→        .map_err(|e| format!("Failed to read registry: {}", e))?;
489→
490→    let json: serde_json::Value = serde_json::from_str(&content)
491→        .map_err(|e| format!("Failed to parse registry JSON: {}", e))?;
492→
493→    let hallmarks = json.get(VOFR_REGISTRY_HALLMARKS)
494→        .and_then(|v| v.as_object())
495→        .ok_or_else(|| "Registry missing 'hallmarks' object".to_string())?;
496→
497→    let mut registry = BTreeMap::new();
498→
499→    for (key, value) in hallmarks {
500→        let hallmark: u32 = key.parse()
501→            .map_err(|e| format!("Invalid hallmark key '{}': {}", key, e))?;
502→
503→        let date = value.get("date")
504→            .and_then(|v| v.as_str())
505→            .ok_or_else(|| format!("Hallmark {} missing 'date'", hallmark))?
506→            .to_string();
507→
508→        let sha = value.get("sha")
509→            .and_then(|v| v.as_str())
510→            .ok_or_else(|| format!("Hallmark {} missing 'sha'", hallmark))?
511→            .to_string();
512→
513→        registry.insert(hallmark, vofr_RegistryEntry { date, sha });
514→    }
515→
516→    Ok(registry)
517→}
518→
519→/// Save registry to JSON file.
520→fn zvofr_save_registry(path: &Path, registry: &BTreeMap<u32, vofr_RegistryEntry>) -> Result<(), String> {
521→    let mut hallmarks = serde_json::Map::new();
522→
523→    for (hallmark, entry) in registry {
524→        let mut entry_obj = serde_json::Map::new();
525→        entry_obj.insert("date".to_string(), serde_json::Value::String(entry.date.clone()));
526→        entry_obj.insert("sha".to_string(), serde_json::Value::String(entry.sha.clone()));
527→        hallmarks.insert(hallmark.to_string(), serde_json::Value::Object(entry_obj));
528→    }
529→
530→    let mut root = serde_json::Map::new();
531→    root.insert(VOFR_REGISTRY_HALLMARKS.to_string(), serde_json::Value::Object(hallmarks));
532→
533→    let json = serde_json::to_string_pretty(&serde_json::Value::Object(root))
534→        .map_err(|e| format!("Failed to serialize registry: {}", e))?;
535→
536→    fs::write(path, json)
537→        .map_err(|e| format!("Failed to write registry: {}", e))?;
538→
539→    Ok(())
540→}
541→
542→/// Find hallmark by SHA.
543→fn zvofr_find_by_sha(registry: &BTreeMap<u32, vofr_RegistryEntry>, sha: &str) -> Option<u32> {
544→    for (hallmark, entry) in registry {
545→        if entry.sha == sha {
546→            return Some(*hallmark);
547→        }
548→    }
549→    None
550→}
551→
552→/// Allocate next sequential hallmark.
553→fn zvofr_allocate_hallmark(registry: &BTreeMap<u32, vofr_RegistryEntry>) -> u32 {
554→    registry.keys().max().map(|m| m + 1).unwrap_or(VOFR_HALLMARK_START)
555→}
556→
557→/// Generate date string in YYMMDD-HHMM format.
558→fn zvofr_generate_date() -> String {
559→    use std::process::Command;
560→
561→    let output = Command::new("date")
562→        .args(["+%y%m%d-%H%M"])
563→        .output()
564→        .expect("Failed to run date command");
565→
566→    String::from_utf8_lossy(&output.stdout).trim().to_string()
567→}
