187→/// Environment gate — panics if Claude Code environment is misconfigured.
188→/// Called unconditionally before any argument parsing or library use.
189→fn vosr_init() {
190→    if std::env::var("CLAUDE_CODE_DISABLE_AUTO_MEMORY").as_deref() != Ok("1") {
191→        panic!("CLAUDE_CODE_DISABLE_AUTO_MEMORY must be 1");
192→    }
193→}
